import * as React from 'react';
import type { UsePinInputProps, PinInputRef } from './usePinInput';
import { usePinInput, PinInputContextProvider, PinInputDescendantsProvider } from './usePinInput';

/**
 * @docgen
 */
export type PinInputProps = UsePinInputProps;

export const PinInput = React.forwardRef<PinInputRef, PinInputProps>((props, ref) => {
  const { children } = props;
  const { descendants, ...contextValue } = usePinInput(props, ref);

  return (
    <PinInputDescendantsProvider value={descendants}>
      <PinInputContextProvider value={contextValue}>{children}</PinInputContextProvider>
    </PinInputDescendantsProvider>
  );
});
